class AccountActor(initialBalance: BigDecimal) extends Actor {
  import AccountActor._

  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount > 0) {
        balance += amount
        sender() ! TransactionResult(true, s"Deposited $amount. New balance: $balance")
      } else {
        sender() ! TransactionResult(false, "Deposit amount must be positive.")
      }

    case Withdraw(amount) =>
      if (amount > 0) {
        if (balance >= amount) {
          balance -= amount
          sender() ! TransactionResult(true, s"Withdrew $amount. New balance: $balance")
        } else {
          sender() ! TransactionResult(false, s"Insufficient funds. Current balance: $balance, requested: $amount")
        }
      } else {
        sender() ! TransactionResult(false, "Withdrawal amount must be positive.")
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
